function getSizeAfterRotation(width, height, angleDeg) {
 const angleRad = angleDeg * Math.PI / 180;
 const cosA = Math.abs(Math.cos(angleRad));
 const sinA = Math.abs(Math.sin(angleRad));
 return {
 width: Math.round((width * cosA + height * sinA) * 100) / 100,
 height: Math.round((width * sinA + height * cosA) * 100) / 100
 };
}
function clampRotation(angle) {
 return Math.max(-180, Math.min(180, angle));
}
function normalizeRotation(angle) {
 let a = angle % 360;
 if (a > 180) a -= 360;
 if (a < -180) a += 360;
 return a;
}
function isRightAngle(angleDeg) {
 return Math.abs(angleDeg % 90) < 1e-3;
}
function getPageDimsAfterRotation(width, height, angleDeg) {
 const normalized = normalizeRotation(angleDeg);
 const abs = Math.abs(normalized);
 if (Math.abs(abs - 90) < 1e-3) {
 return { width: height, height: width };
 }
 if (abs < 1e-3 || Math.abs(abs - 180) < 1e-3) {
 return { width, height };
 }
 return getSizeAfterRotation(width, height, angleDeg);
}
function sourcePointToVisual(sx, sy, origW, origH, rotDeg, flipH, flipV) {
 let px = sx - origW / 2;
 let py = sy - origH / 2;
 if (flipH) px = -px;
 if (flipV) py = -py;
 const angle = normalizeRotation(rotDeg);
 let rx, ry;
 if (Math.abs(angle) < 1e-3) {
 rx = px;
 ry = py;
 } else if (Math.abs(angle - 90) < 1e-3) {
 rx = -py;
 ry = px;
 } else if (Math.abs(angle + 90) < 1e-3) {
 rx = py;
 ry = -px;
 } else if (Math.abs(Math.abs(angle) - 180) < 1e-3) {
 rx = -px;
 ry = -py;
 } else {
 const rad = angle * Math.PI / 180;
 rx = px * Math.cos(rad) - py * Math.sin(rad);
 ry = px * Math.sin(rad) + py * Math.cos(rad);
 }
 const isSwap = Math.abs(Math.round(angle / 90)) % 2 === 1;
 const visualW = isSwap ? origH : origW;
 const visualH = isSwap ? origW : origH;
 return { x: visualW / 2 + rx, y: visualH / 2 + ry };
}
function visualPointToSource(vx, vy, origW, origH, rotDeg, flipH, flipV) {
 const angle = normalizeRotation(rotDeg);
 const isSwap = Math.abs(Math.round(angle / 90)) % 2 === 1;
 const visualW = isSwap ? origH : origW;
 const visualH = isSwap ? origW : origH;
 const rx = vx - visualW / 2;
 const ry = vy - visualH / 2;
 let px, py;
 if (Math.abs(angle) < 1e-3) {
 px = rx;
 py = ry;
 } else if (Math.abs(angle - 90) < 1e-3) {
 px = ry;
 py = -rx;
 } else if (Math.abs(angle + 90) < 1e-3) {
 px = -ry;
 py = rx;
 } else if (Math.abs(Math.abs(angle) - 180) < 1e-3) {
 px = -rx;
 py = -ry;
 } else {
 const rad = -angle * Math.PI / 180;
 px = rx * Math.cos(rad) - ry * Math.sin(rad);
 py = rx * Math.sin(rad) + ry * Math.cos(rad);
 }
 if (flipH) px = -px;
 if (flipV) py = -py;
 return { x: px + origW / 2, y: py + origH / 2 };
}
function sourceCropToVisual(crop, origW, origH, rotDeg, flipH, flipV) {
 const p1 = sourcePointToVisual(crop.x, crop.y, origW, origH, rotDeg, flipH, flipV);
 const p2 = sourcePointToVisual(
 crop.x + crop.width,
 crop.y + crop.height,
 origW,
 origH,
 rotDeg,
 flipH,
 flipV
 );
 const minX = Math.min(p1.x, p2.x);
 const minY = Math.min(p1.y, p2.y);
 return {
 x: minX,
 y: minY,
 width: Math.max(p1.x, p2.x) - minX,
 height: Math.max(p1.y, p2.y) - minY
 };
}
function visualCropToSource(crop, origW, origH, rotDeg, flipH, flipV) {
 const p1 = visualPointToSource(crop.x, crop.y, origW, origH, rotDeg, flipH, flipV);
 const p2 = visualPointToSource(
 crop.x + crop.width,
 crop.y + crop.height,
 origW,
 origH,
 rotDeg,
 flipH,
 flipV
 );
 const minX = Math.min(p1.x, p2.x);
 const minY = Math.min(p1.y, p2.y);
 return {
 x: minX,
 y: minY,
 width: Math.max(p1.x, p2.x) - minX,
 height: Math.max(p1.y, p2.y) - minY
 };
}

